'use client';

import { motion, useMotionValue, animate } from 'framer-motion';
import { useEffect } from 'react';

export function CursorAura() {
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const scale = useMotionValue(1);

  useEffect(() => {
    const move = (e: MouseEvent) => {
      const { clientX, clientY } = e;

      const target = document.elementFromPoint(clientX, clientY);

      // 🔥 Magnetic effect
      if (target?.closest('[data-magnetic]')) {
        const rect = target.getBoundingClientRect();

        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        animate(x, centerX, { type: 'spring', stiffness: 200 });
        animate(y, centerY, { type: 'spring', stiffness: 200 });

        animate(scale, 1.6, { duration: 0.2 });
      } else {
        animate(x, clientX, { duration: 0.25 });
        animate(y, clientY, { duration: 0.25 });

        animate(scale, 1, { duration: 0.3 });
      }
    };

    window.addEventListener('mousemove', move);
    return () => window.removeEventListener('mousemove', move);
  }, []);

  return (
    <motion.div className='pointer-events-none fixed inset-0 z-0'>
      <motion.div
        style={{ x, y, scale }}
        className='-translate-x-1/2 -translate-y-1/2 w-64 h-64 rounded-full relative'
      >
        {/* 🔥 Gradient masked by dots */}
        <div
          className='absolute inset-0 rounded-full'
          style={{
            background:
              'radial-gradient(circle at 30% 30%, rgba(255,140,0,0.7), rgba(255,0,150,0.6), rgba(0,200,255,0.6), transparent)',

            WebkitMaskImage:
              'radial-gradient(circle, black 60%, transparent 100%), radial-gradient(white 1px, transparent 1px)',
            WebkitMaskComposite: 'destination-in',

            maskImage:
              'radial-gradient(circle, black 60%, transparent 100%), radial-gradient(white 1px, transparent 1px)',
            maskComposite: 'intersect',

            maskSize: '100% 100%, 10px 10px',
            WebkitMaskSize: '100% 100%, 10px 10px',

            filter: 'blur(10px)',
          }}
        />

        {/* 🔥 Soft glow */}
        <div className='absolute inset-0 rounded-full bg-amber-400/10 blur-2xl' />
      </motion.div>
    </motion.div>
  );
}
